VALUES
  ('optician-moex-00259', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一患者之遠點距離為眼鏡前20公分， 假設頂點距離為15mm，此病患應配戴之隱形眼鏡度數為何？', '["-2.86D", "-4.65D", "-5.00D", "-5.41D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00260', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '下列那兩者的鏡片度數是一模一樣的？', '["-4.75DS/-1.75DC 180與-4.75DS/-1.75DC 90", "-3.50DS/-0.75DC 180與-4.25DS/+0.75DC 180 × ×", "+6.25DS/+1.25DC 90與+7.50DS/-1.25DC 90 × ×", "-1.50DS/+3.00DC 180與+1.50DS/-3.00DC 90 × ×"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00261', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '關於光的折射（lightrefraction），下列何者錯誤？ × ×', '["當光從光疏介質（低折射率）進入光密介質（高折射率）時，頻率降低，光速減慢，波長縮短，折 射角減小，折射率減小，光線偏向法線", "如果光線的行進方向相反，光線將沿著原來完全相同的路徑傳播回原來的位置。稱為可逆性原理 （principleofreversibility）", "光線從光密介質進入光疏介質時，折射角會變大。當入射角達到一定角度時，折射角就會變成90°。 此時的入射角稱為臨界角（criticalangle）", "當入射光在光密介質中的入射角大於臨界角時，入射光將全部反射回原介質，不能折射到光疏介質 中，稱為全內反射（totalinternalreflection）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00262', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一個屈光度為+6.00 D的球面介面分開前面的空氣和後面的玻璃（折射率1.5），其球面的第一焦點和 第二焦點分別位在何處？', '["前者在球面的前方（空氣）16.7cm處；後者在球面的後方（玻璃）25.0cm處", "前者在球面的後方（玻璃）16.7cm處；後者在球面的後方（玻璃）25.0cm處", "前者在球面的前方（空氣）16.7cm處；後者在球面的前方（空氣）25.0cm處", "前者在球面的前方（空氣）25.0cm處；後者在球面的後方（玻璃）16.7cm處"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00263', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '有一道垂直偏振的光線入射完美的平面式偏光太陽眼鏡，此太陽眼鏡之吸收軸距離垂直偏正軸約 25 度，則此太陽眼鏡之光線穿透率約為多少？', '["9.89%", "12.51%", "17.86%", "19.78%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00264', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '光線由空氣入射折射率為1.523的平片鏡片，其入射角度需要多少，才可以使得反射光線與折射光線 互相垂直？', '["32.87", "43.56", "51.75", "56.71"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00265', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '有一高度為10cm的物體在第一焦距前方20cm處，當鏡片屈光度數為+5.00D時，影像的高度為下 ° ° ° ° 列何者？', '["不成像", "5cm", "10cm", "15cm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00266', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '小明右眼屈光度數：-3.50DS/+0.75DC 90，角膜弧度為7.80mm/7.65mm，戴上基弧為7.65mm，屈 光度數為零的RGP片後，驗光為多少度？ ×', '["-3.50D", "-3.25D", "-2.75D", "-2.00D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00267', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一屈光力為-6.00D新月凹薄透鏡，其前後表面曲率半徑分別為10公分和5公分，鏡片材質的折射率 為何？', '["1.33", "1.5", "1.6", "1.8"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00268', 'optician', 'optician-moex-113-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '當光從低密度介質進入到高密度介質，光波的傳播速率會減慢，下列敘述何者錯誤？', '["因波長減少", "因頻率減少", "因折射率增大", "因入射角大於折射角"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "23b5f86bd168", "answer_pdf_sha1": "8fe215b9747c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
